INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (1, 'Arco', 'Sarca Valley', 'Italy', 'Year-round sport climbing on grey and orange limestone above Lake Garda — hundreds of bolted lines from slabby warm-ups to steep tufa testpieces.', '2026-06-15 08:53:53.637843+00', false, 1);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (2, 'Kalymnos', 'Dodecanese', 'Greece', 'A Greek island of steep grey and orange limestone dripping with tufas and stalactites, rising straight out of the Aegean. The sport-climbing holiday classic.', '2026-06-15 08:53:53.647411+00', false, 1);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (3, 'Fontainebleau', 'Île-de-France', 'France', 'The spiritual home of bouldering: a forest of sandstone boulders south of Paris, famous for slopers, delicate slabs and impeccable friction.', '2026-06-15 08:53:53.654348+00', false, 1);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (4, 'Finale Ligure', 'Liguria', 'Italy', 'Sunny seaside limestone above the Riviera — thousands of routes on pockets and tufas, climbable all winter.', '2026-06-15 11:56:48.881207+00', false, 2);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (5, 'Sperlonga', 'Lazio', 'Italy', 'Steep grey limestone overlooking the Tyrrhenian Sea, halfway between Rome and Naples. A winter sport-climbing hotspot.', '2026-06-15 11:56:48.881207+00', false, 2);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (6, 'San Vito Lo Capo', 'Sicily', 'Italy', 'Golden limestone crags by a white-sand beach on Sicily''s northwest tip — the venue for the annual climbing festival.', '2026-06-15 11:56:48.881207+00', false, 2);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (7, 'Val di Mello', 'Lombardy', 'Italy', 'A granite valley of slabs and cracks in the Italian Alps — Yosemite-style trad and bouldering amid pastures.', '2026-06-15 11:56:48.881207+00', false, 2);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (8, 'Leonidio', 'Peloponnese', 'Greece', 'A vast amphitheatre of orange and grey limestone above the Myrtoan Sea — Greece''s fastest-growing sport destination.', '2026-06-15 11:56:48.881207+00', false, 2);
